**Three fixes in AuthContext.jsx:**

**Fix 1: Wrap `fetchProfile` in try/catch (lines 16-28)**
```js
const fetchProfile = async (userId) => {
  try {
    const { data, error } = await supabase
      .from('profiles')
      .select('id, display_name, email, avatar_url, created_at')
      .eq('id', userId)
      .single();
    if (error) {
      console.error('Failed to fetch profile:', error);
      return null;
    }
    return data;
  } catch (err) {
    console.error('Failed to fetch profile (network):', err);
    return null;
  }
};
```

**Fix 2: Add `.catch()` to `getSession().then()` (line 50)**
```js
supabase.auth.getSession().then(async ({ data: { session } }) => {
  if (session?.user) {
    const profile = await fetchProfile(session.user.id);
    setUser(mergeUserWithProfile(session.user, profile));
  }
  setIsLoading(false);
}).catch((err) => {
  console.error('Failed to get session:', err);
  setIsLoading(false);
});
```

**Fix 3: Add a timeout fallback**
```js
